import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as t,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Image Moderation และ Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Safety/image-moderation-and-access-mode.md","filePath":"th-TH/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),r={name:"th-TH/Safety/image-moderation-and-access-mode.md"};function o(s,e,n,c,m,p){return t(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="image-moderation-และ-access-mode" tabindex="-1">Image Moderation และ Access Mode <a class="header-anchor" href="#image-moderation-และ-access-mode" aria-label="Permalink to &quot;Image Moderation และ Access Mode&quot;">​</a></h1><p>Image moderation กำหนด age rating ให้ uploaded images ส่วน Access mode ควบคุมว่า ratings ใดสามารถมองเห็นผ่าน public access</p><p>มีผลกับ public gallery, public file URLs และ random image API แต่ไม่จำกัด admin panel Administrators ยังดูและ manage files ได้ทั้งหมด</p><h2 id="ตั้งค่าที่ไหน" tabindex="-1">ตั้งค่าที่ไหน <a class="header-anchor" href="#ตั้งค่าที่ไหน" aria-label="Permalink to &quot;ตั้งค่าที่ไหน&quot;">​</a></h2><p>เปิด admin panel แล้วไปที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Settings หลัก:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-ทําอะไร" tabindex="-1">Access Mode ทำอะไร <a class="header-anchor" href="#access-mode-ทําอะไร" aria-label="Permalink to &quot;Access Mode ทำอะไร&quot;">​</a></h2><p>Access mode ตัดสินว่า age ratings ใดแสดงแบบ public ได้</p><p>Current modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>เฉพาะ General</td></tr></tbody></table><p>Default คือ Adult mode</p><p>สำหรับ private sites หรือ sites ที่มี mature content Adult mode อาจเหมาะสม ถ้าต้องการ public gallery ที่ conservative กว่า ให้เลือก Youth, Teen หรือ Child mode</p><h2 id="enable-moderation-แล้วเกิดอะไร" tabindex="-1">Enable Moderation แล้วเกิดอะไร <a class="header-anchor" href="#enable-moderation-แล้วเกิดอะไร" aria-label="Permalink to &quot;Enable Moderation แล้วเกิดอะไร&quot;">​</a></h2><p>เมื่อ moderation enabled ImgBed จะ call selected moderation provider ตอน upload และ save age rating ที่ตรวจพบ</p><p>Ratings หลัก:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>Safe public content</td></tr><tr><td>R12</td><td>Content ที่ sensitive เล็กน้อย</td></tr><tr><td>R16</td><td>Content ที่ sensitive ปานกลาง</td></tr><tr><td>R18</td><td>Adult content</td></tr></tbody></table><p>Moderation result ใช้ตอนตัดสิน public access</p><p>ถ้าไม่ได้ enable moderation หรือ files เก่าไม่มี rating files เหล่านั้นจะถือเป็น unrated Unrated files จะไม่ถูกเอาออกจาก public gallery หรือ random image API อัตโนมัติเพียงเพราะไม่มี rating</p><h2 id="เลือก-moderation-provider" tabindex="-1">เลือก Moderation Provider <a class="header-anchor" href="#เลือก-moderation-provider" aria-label="Permalink to &quot;เลือก Moderation Provider&quot;">​</a></h2><p>Available providers:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>แต่ละ provider มี requirements ต่างกัน:</p><ul><li>moderatecontent.com มักต้องใช้ API Key</li><li>nsfwjs มักต้องใช้ API endpoint URL</li><li>Sightengine ต้องใช้ API user และ API secret</li></ul><p>เลือกตาม account, availability และ detection quality ของคุณ ตราบใดที่ moderation enabled และ configured ถูกต้อง ImgBed จะพยายามเขียน image rating ตอน upload</p><h2 id="ผลต่อ-public-gallery" tabindex="-1">ผลต่อ Public Gallery <a class="header-anchor" href="#ผลต่อ-public-gallery" aria-label="Permalink to &quot;ผลต่อ Public Gallery&quot;">​</a></h2><p>Public gallery filter files ตาม access mode</p><p>Examples:</p><ul><li>Adult mode: R18 images แสดงได้</li><li>Youth mode: R18 images ถูกซ่อน</li><li>Teen mode: R16 และ R18 images ถูกซ่อน</li><li>Child mode: แสดงเฉพาะ General images</li></ul><p>มีผลเฉพาะ normal public access Admin panel ยังแสดง files ทั้งหมด</p><h2 id="ผลต่อ-public-file-urls" tabindex="-1">ผลต่อ Public File URLs <a class="header-anchor" href="#ผลต่อ-public-file-urls" aria-label="Permalink to &quot;ผลต่อ Public File URLs&quot;">​</a></h2><p>Public file URLs คือ direct image links ที่ visitors เปิด</p><p>ถ้า file rating allowed ตาม current access mode ImgBed จะ return original image</p><p>ถ้า rating สูงกว่า allowed level normal public access จะไม่ return original image แต่ ImgBed จะ return configured blocked result หรือ blocked fallback image แทน</p><p>Example:</p><ul><li>Current mode คือ Child mode</li><li>Image หนึ่งมี rating R18</li><li>Visitor เปิด public URL โดยตรง</li><li>ImgBed ไม่ return R18 original image ให้ visitor นั้น</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>Administrators ที่ดู files ใน admin panel จะไม่ได้รับผลจาก restriction นี้</p><h2 id="ผลต่อ-random-image-api" tabindex="-1">ผลต่อ Random Image API <a class="header-anchor" href="#ผลต่อ-random-image-api" aria-label="Permalink to &quot;ผลต่อ Random Image API&quot;">​</a></h2><p>Random image API ก็ filter candidate pool ตาม access mode เช่นกัน</p><p>ใน Child mode random images จะเลือกจาก General-rated files เท่านั้น</p><p>ใน Youth mode random images อาจมาจาก General, R12 และ R16 files แต่ไม่รวม R18 files</p><p>ช่วยป้องกันไม่ให้ random image API bypass public gallery restrictions</p><h2 id="ความสัมพันธ์กับ-list-rules" tabindex="-1">ความสัมพันธ์กับ List Rules <a class="header-anchor" href="#ความสัมพันธ์กับ-list-rules" aria-label="Permalink to &quot;ความสัมพันธ์กับ List Rules&quot;">​</a></h2><p>Access mode ไม่ใช่ public access rule เดียว แต่ทำงานร่วมกับ allow/block list rules</p><p>สรุปง่าย ๆ:</p><ul><li>Allowlisted content เป็น public ก่อน</li><li>Blocklisted content ไม่สามารถดูตรง ๆ โดย regular visitors</li><li>Content ที่ไม่อยู่ใน list ใด ๆ จะถูกตรวจตาม access mode</li></ul><p>ถ้า image ถูกจำกัดทั้งด้วย age rating และ list rules regular visitors ก็ยังดู original file โดยตรงไม่ได้</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>สำหรับ public sites:</p><ul><li>Enable moderation</li><li>เลือก access mode ให้ตรงกับ audience ของ site</li><li>ใช้ Child mode หรือ Teen mode สำหรับ visitors ทุกวัย</li><li>หลีกเลี่ยง Adult mode หากไม่ต้องการแสดง mature content แบบ public</li><li>Review file ratings ใน admin panel และ adjust manually เมื่อจำเป็น</li></ul><p>สำหรับ private หรือ personal sites:</p><ul><li>Adult mode มักใช้ได้</li><li>Enable moderation ถ้ามีประโยชน์</li><li>Review และ adjust ratings ใน admin panel ตามต้องการ</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="เปลี่ยน-access-mode-แล้ว-files-จะหายจาก-admin-panel-ไหม" tabindex="-1">เปลี่ยน Access Mode แล้ว Files จะหายจาก Admin Panel ไหม? <a class="header-anchor" href="#เปลี่ยน-access-mode-แล้ว-files-จะหายจาก-admin-panel-ไหม" aria-label="Permalink to &quot;เปลี่ยน Access Mode แล้ว Files จะหายจาก Admin Panel ไหม?&quot;">​</a></h3><p>ไม่</p><p>Access mode มีผลเฉพาะ normal public access ไม่มีผลกับ admin panel</p><h3 id="ทําไม-public-gallery-แสดง-images-น้อยลงหลังเปลี่ยนเป็น-child-mode" tabindex="-1">ทำไม Public Gallery แสดง Images น้อยลงหลังเปลี่ยนเป็น Child Mode? <a class="header-anchor" href="#ทําไม-public-gallery-แสดง-images-น้อยลงหลังเปลี่ยนเป็น-child-mode" aria-label="Permalink to &quot;ทำไม Public Gallery แสดง Images น้อยลงหลังเปลี่ยนเป็น Child Mode?&quot;">​</a></h3><p>Child mode อนุญาตให้แสดงเฉพาะ General-rated files แบบ public R12, R16 และ R18 files จะถูก filter ออก</p><h3 id="public-urls-ยังเปิด-adult-images-ได้ไหม" tabindex="-1">Public URLs ยังเปิด Adult Images ได้ไหม? <a class="header-anchor" href="#public-urls-ยังเปิด-adult-images-ได้ไหม" aria-label="Permalink to &quot;Public URLs ยังเปิด Adult Images ได้ไหม?&quot;">​</a></h3><p>ถ้า current access mode ไม่อนุญาต rating นั้น normal public URLs จะไม่ return original image</p><h3 id="random-image-api-return-restricted-images-ได้ไหม" tabindex="-1">Random Image API Return Restricted Images ได้ไหม? <a class="header-anchor" href="#random-image-api-return-restricted-images-ได้ไหม" aria-label="Permalink to &quot;Random Image API Return Restricted Images ได้ไหม?&quot;">​</a></h3><p>ไม่ได้</p><p>Random image API filter candidates ตาม current access mode</p><h3 id="old-unrated-images-จะเป็นอย่างไร" tabindex="-1">Old Unrated Images จะเป็นอย่างไร? <a class="header-anchor" href="#old-unrated-images-จะเป็นอย่างไร" aria-label="Permalink to &quot;Old Unrated Images จะเป็นอย่างไร?&quot;">​</a></h3><p>Unrated images จะไม่ถูกซ่อนอัตโนมัติเพียงเพราะไม่มี moderation results คุณสามารถ adjust ratings ใน admin panel ภายหลังได้</p>',67)])])}const b=i(r,[["render",o]]);export{h as __pageData,b as default};
